def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                base = np.sin(ratio * a * np.pi) ** 2 + np.cos(ratio * (a+1))
                weight = (a ** 2) / (a + 3)
                score += base * weight
            if (capacity % 4 == 0 and item % 2 == 1):
                score *= 0.85
            if score > 12:
                score /= 3
        elif 0.05 <= ratio < 0.2:
            sum_val = 0
            for n in range(1, int(capacity) + 5):
                exp_val = np.exp(-ratio * n / (n+0.5))
                log_val = np.log1p(n + ratio)
                sum_val += exp_val * log_val / (n + 1)
                if sum_val > 5000:
                    sum_val = np.sqrt(sum_val)
                    break
            mod_val = int(sum_val * 7) % 250
            score += np.sqrt(mod_val + ratio * 10)
            if (int(capacity) % 5 == 0) or (int(item*3) % 4 == 0):
                score += 3.7
            else:
                score -= 1.2
            extra_calc = 0
            for x in range(1, 8):
                frac_part = (ratio * x**3) % 1
                extra_calc += frac_part * (x ** 1.8)
            score += extra_calc / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                power = (ratio + 0.1) ** (m + 1.5)
                mult = (m ** 2.3) / ((m + 1) ** 0.8)
                score += power * mult
            remainder = abs(capacity - item * 0.95)
            if remainder < 4:
                score += 12 - remainder * 0.4
            else:
                score -= remainder * 0.7
            if score < -10:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 8 == 0:
                score *= 1.3
            if score > 20:
                score /= 4
        elif 0.5 < ratio <= 0.75:
            penalty = 0
            for p in range(1, 15):
                penalty += ((ratio - 0.5) ** p) * (p ** 1.3)
                if penalty > 60:
                    penalty = np.log1p(penalty) * 1.15
                    break
            score = penalty * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 10 == 0):
                score -= 8
            if score < 0:
                score *= -1.2
                score += 6
            if score > 125:
                score = 125
        elif 0.75 < ratio <= 1.25:
            ext_penalty = 0
            diff = ratio - 0.75
            for q in range(1, 13):
                ext_penalty += ((diff) ** q) * (q ** 2.9) / (q + 0.8)
                if ext_penalty > 1500:
                    ext_penalty = np.sqrt(ext_penalty) * 1.3
                    break
            score = ext_penalty * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.0)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1500:
                score = 1500
        elif 1.25 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.2) / (r + 0.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 22
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 10) % 5 == 0) and (int(item * 15) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.65 + 5
            if score > 2500:
                score = 2500
        else:
            ultra_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 18):
                term = ((diff ** s) * (s ** 3.5)) / (s ** 0.7)
                if term > 20000:
                    term = np.cbrt(term) * 1.2
                ultra_penalty += term
            score = ultra_penalty * 30
            if capacity < item * 3:
                score += 40
            if (int(capacity * 20) % 7 == 0) and (int(item * 25) % 8 == 0):
                score -= 14
            for v in range(4, 12):
                score += ((diff / (v + 0.4)) % 1) * (v * 3)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 10:
            score *= 2.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        high_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + high_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    return priorities
